#include<bits/stdc++.h>
using namespace std;
int n,a,b;
int max1[101][101],min1[101][101];
int main()
{
    scanf("%d%d%d",&n,&a,&b);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            char ch;
            cin>>ch;
            if(ch=='='||i==j)
            {
                min1[i][j]=max1[i][j]=0;
            }
            else if(ch=='+')
            {
                max1[i][j]=2;
                min1[i][j]=1;
            }
            else if(ch=='-')
            {
                max1[i][j]=-1;
                min1[i][j]=-2;
            }
            else
            {
                max1[i][j]=2;
                min1[i][j]=-2;
            }
        }
    }
    for(int k=1;k<=n;k++)
    {
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                max1[i][j]=min(max1[i][j],max1[i][k]+max1[k][j]);
                min1[i][j]=max(min1[i][j],min1[i][k]+min1[k][j]);
            }
        }
    }
    int c1=0,c2=0,c3=0;
    for(int i=1;i<=n;i++)if(i!=a&&i!=b)
    {
        for(int j=1;j<i;j++)if(j!=a&&j!=b)
        {
            if(min1[a][i]>max1[j][b]||min1[a][j]>max1[i][b])
            {
                c1++;
            }
            if(min1[a][i]==max1[a][i]&&min1[a][i]==min1[j][b]&&min1[j][b]==max1[j][b])
            {
                c2++;
            }
            else if(min1[b][i]==max1[b][i]&&min1[b][i]==min1[j][a]&&min1[j][a]==max1[j][a])
            {
                c2++;
            }
            if(max1[a][i]<min1[j][b]||max1[a][j]<min1[i][b])
            {
                c3++;
            }
        }
    }
    printf("%d %d %d",c1,c2,c3);
    return 0;
}
